prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoName (COUNT(DISTINCT ?end) AS ?endCount) WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "4ccc3fd711004f519782ac92e58f6ddd" ;
         tai:belongsTo ?org .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?end a bboExt:EndEvent ;
       tai:belongsTo ?choreo .
  OPTIONAL { ?choreo bbo:name ?choreoName . }
}
GROUP BY ?choreo ?choreoName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?idProp ?idValue ?org WHERE {
  ?model a bboExt:Model .
  ?model tai:belongsTo ?org .
  OPTIONAL { ?model bbo:name ?modelName . }
  { ?model tai:normalizedId ?idValue . BIND("normalizedId" AS ?idProp) }
  UNION
  { ?model tai:originalId ?idValue . BIND("originalId" AS ?idProp) }
  FILTER(STR(?idValue) = "4ccc3fd711004f519782ac92e58f6ddd")
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?startName ?choreo ?start ?endExists WHERE {
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  BIND(exists {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?end .
    ?end a bboExt:EndEvent ;
         tai:belongsTo ?choreo .
  } AS ?endExists)
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?start ?startName WHERE {
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  FILTER NOT EXISTS {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?end .
    ?end a bboExt:EndEvent ;
         tai:belongsTo ?choreo .
  }
}
LIMIT 25
